INSERT IGNORE INTO `tcf_ee_consignes` (`id`, `title`, `body`, `task_key`, `visibility`, `is_published`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (15,'Instructions g├®n├®rales','L\'├®preuve d\'expression ├®crite du TCF Canada ├®value votre capacit├® ├á vous exprimer en fran├ºais dans des situations de la vie quotidienne.\nCette ├®preuve comprend 3 t├óches de difficult├® progressive qui simulent des situations r├®elles de communication.','general','gratuit',1,1,1,'2026-05-09 08:33:25',NULL),(16,'Important','Vous disposerez de 15 minutes de pr├®paration avant l\'├®preuve.\nPendant l\'├®preuve, chaque temps de parole est strictement chronom├®tr├®.\nL\'examinateur enregistrera vos r├®ponses pour ├®valuation.','general','gratuit',1,2,1,'2026-05-09 08:33:25',NULL),(20,'Crit├¿res d\'├®valuation','Correction grammaticale : ma├«trise des structures de base de la langue.\nRichesse lexicale : ├®tendue et pr├®cision du vocabulaire utilis├®.\nPrononciation : clart├® de l\'articulation et intonation.\nMa├«trise discursive : capacit├® ├á organiser et encha├«ner ses id├®es.\nInteraction : capacit├® ├á comprendre et r├®agir aux sollicitations.','general','gratuit',1,6,1,'2026-05-09 08:33:25',NULL),(21,'Conseil 1','G├®rez bien votre temps de pr├®paration : notez des id├®es cl├®s, pas des phrases enti├¿res.','general','gratuit',1,7,1,'2026-05-09 08:33:25',NULL),(22,'Conseil 2','Parlez distinctement et ├á un rythme naturel, ni trop vite ni trop lentement.','general','gratuit',1,8,1,'2026-05-09 08:33:25',NULL),(23,'Conseil 3','Utilisez des formules de politesse adapt├®es aux situations propos├®es et variez les structures grammaticales.','general','gratuit',1,9,1,'2026-05-09 08:33:25',NULL),(24,'Conseil 4','Structurez vos r├®ponses : introduction, d├®veloppement, conclusion (surtout pour la t├óche 3).','general','gratuit',1,10,1,'2026-05-09 08:33:25',NULL),(25,'T├óche 1','<h2>Consignes pour l\'├®preuve d\'Expression ├ëcrite</h2>\n\n<div class=\"consigne-section\">\n    <h3>­ƒôï Informations g├®n├®rales</h3>\n    <ul>\n        <li><strong>Dur├®e :</strong> 60 minutes</li>\n        <li><strong>Nombre de t├óches :</strong> 3 t├óches</li>\n        <li><strong>Support :</strong> Documents ├®crits (lettres, emails, articles)</li>\n        <li><strong>Objectif :</strong> ├ëvaluer votre capacit├® ├á produire des ├®crits en fran├ºais</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒôÜ Structure de l\'├®preuve</h3>\n    <p>L\'├®preuve se compose de trois t├óches progressives :</p>\n    \n    <h4>T├óche 1 : ├ëcrire un message (15 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Situation de la vie quotidienne ou professionnelle</li>\n        <li><strong>Type :</strong> Lettre, email, message</li>\n        <li><strong>Longueur :</strong> Environ 50 mots</li>\n        <li><strong>Objectif :</strong> Transmettre une information simple</li>\n    </ul>\n    \n    <h4>T├óche 2 : R├®diger un texte argumentatif (45 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Sujet d\'actualit├® ou probl├¿me de soci├®t├®</li>\n        <li><strong>Type :</strong> Article, essai, opinion</li>\n        <li><strong>Longueur :</strong> Environ 180 mots</li>\n        <li><strong>Objectif :</strong> Exprimer et d├®fendre un point de vue</li>\n    </ul>\n    \n    <h4>T├óche 3 : Synth├¿se de documents (60 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Deux ou trois documents sur un m├¬me th├¿me</li>\n        <li><strong>Type :</strong> Synth├¿se ├®crite</li>\n        <li><strong>Longueur :</strong> Environ 250 mots</li>\n        <li><strong>Objectif :</strong> R├®sumer et comparer les informations</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒÆí Conseils pour r├®ussir</h3>\n    <ul>\n        <li>Lisez attentivement le sujet et rep├®rez les mots-cl├®s</li>\n        <li>Respectez scrupuleusement le nombre de mots demand├®</li>\n        <li>Structurez votre texte : introduction, d├®veloppement, conclusion</li>\n        <li>Utilisez des connecteurs logiques (cependant, par cons├®quent, en effet)</li>\n        <li>Variez le vocabulaire et les structures grammaticales</li>\n        <li>Relisez votre texte pour corriger les fautes d\'orthographe</li>\n        <li>Adaptez votre ton au contexte (formel ou informel)</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒÄ» Crit├¿res d\'├®valuation</h3>\n    <ul>\n        <li><strong>Respect du sujet :</strong> R├®pondre ├á la question pos├®e</li>\n        <li><strong>Coh├®rence :</strong> Organisation logique du texte</li>\n        <li><strong>Richesse lexicale :</strong> Vocabulaire vari├® et pr├®cis</li>\n        <li><strong>Correction grammaticale :</strong> Syntaxe et conjugaison</li>\n        <li><strong>Orthographe :</strong> Respect des r├¿gles d\'├®criture</li>\n    </ul>\n</div>','tache1','gratuit',1,1,1,'2026-05-09 11:03:04','2026-07-11 20:45:17'),(26,'T├óche 2','Vous devrez obtenir des informations dans une situation de la vie courante (2 minutes 30).\r\nCette t├óche ├®value votre capacit├® ├á interagir dans un contexte pratique.','tache2','gratuit',1,2,1,'2026-05-09 11:03:04',NULL),(27,'T├óche 3','Vous pr├®senterez votre opinion sur un sujet donn├® (3 minutes 30).\r\nCette partie ├®value votre capacit├® ├á argumenter et ├á structurer votre discours.','tache3','gratuit',1,3,1,'2026-05-09 11:03:04',NULL);
