INSERT IGNORE INTO `tcf_eo_consignes` (`id`, `title`, `body`, `task_key`, `visibility`, `is_published`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (1,'T├óche 1','Entretien dirig├® : r├®pondez sur vous-m├¬me et votre quotidien.','tache1','gratuit',1,1,1,'2026-05-09 11:31:45',NULL),(2,'T├óche 2','<h2>Consignes pour l\'├®preuve d\'Expression Orale</h2>\n\n<div class=\"consigne-section\">\n    <h3>­ƒôï Informations g├®n├®rales</h3>\n    <ul>\n        <li><strong>Dur├®e :</strong> 15 minutes</li>\n        <li><strong>Nombre de t├óches :</strong> 3 t├óches</li>\n        <li><strong>Support :</strong> Documents visuels ou th├®matiques</li>\n        <li><strong>Objectif :</strong> ├ëvaluer votre capacit├® ├á s\'exprimer oralement en fran├ºais</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒôÜ Structure de l\'├®preuve</h3>\n    <p>L\'├®preuve se compose de trois t├óches progressives :</p>\n    \n    <h4>T├óche 1 : Entretien dirig├® (2 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Questions personnelles sur votre vie</li>\n        <li><strong>Th├¿mes :</strong> ├ëtudes, travail, loisirs, projets</li>\n        <li><strong>Objectif :</strong> Pr├®senter bri├¿vement votre situation</li>\n    </ul>\n    \n    <h4>T├óche 2 : Expos├® (5 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Document visuel (photo, graphique)</li>\n        <li><strong>Pr├®paration :</strong> 2 minutes de pr├®paration</li>\n        <li><strong>Objectif :</strong> D├®crire et commenter un document</li>\n    </ul>\n    \n    <h4>T├óche 3 : D├®bat (8 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Sujet d\'actualit├® ou probl├¿me de soci├®t├®</li>\n        <li><strong>Pr├®paration :</strong> 2 minutes de pr├®paration</li>\n        <li><strong>Objectif :</strong> Exprimer et d├®fendre un point de vue</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒÆí Conseils pour r├®ussir</h3>\n    <ul>\n        <li>Parlez clairement et ├á un rythme mod├®r├®</li>\n        <li>Structurez votre expos├® : introduction, d├®veloppement, conclusion</li>\n        <li>Utilisez des connecteurs logiques (d\'abord, ensuite, enfin)</li>\n        <li>Donnez des exemples concrets pour illustrer vos propos</li>\n        <li>N\'h├®sitez pas ├á demander de r├®p├®ter si vous n\'avez pas compris</li>\n        <li>Exprimez votre opinion personnellement (je pense, ├á mon avis)</li>\n        <li>G├®rez votre temps : ne d├®passez pas le temps imparti</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>­ƒÄ» Crit├¿res d\'├®valuation</h3>\n    <ul>\n        <li><strong>Fluence :</strong> Fluidit├® et aisance de l\'expression</li>\n        <li><strong>Richesse lexicale :</strong> Vocabulaire vari├® et pr├®cis</li>\n        <li><strong>Correction grammaticale :</strong> Syntaxe et conjugaison</li>\n        <li><strong>Prononciation :</strong> Intelligibilit├® de la parole</li>\n        <li><strong>Coh├®rence :</strong> Organisation du discours</li>\n        <li><strong>Interaction :</strong> Capacit├® ├á ├®changer avec l\'examinateur</li>\n    </ul>\n</div>','tache2','gratuit',1,2,1,'2026-05-09 11:31:45','2026-07-11 20:45:17'),(3,'T├óche 3','Point de vue : exprimer et d├®fendre une opinion de fa├ºon structur├®e.','tache3','gratuit',1,3,1,'2026-05-09 11:31:45',NULL);
